function fb(a, b) { if (a) { return a; } return b; }
var topic = fb($.input.topic, '');
var keywords = fb($.input.keywords, '');
var tone = fb($.input.tone, 'informative and engaging');
var wordCount = fb($.input.wordCount, 1500);

var prompt = 'You are an expert blog writer and SEO specialist. Write a complete, publish-ready blog post.\n\n';
prompt += 'TOPIC: ' + topic + '\n';
if (keywords) prompt += 'TARGET KEYWORDS: ' + keywords + '\n';
prompt += 'TONE: ' + tone + '\n';
prompt += 'TARGET WORD COUNT: ' + wordCount + '\n\n';
prompt += 'REQUIREMENTS:\n';
prompt += '- Write in HTML format suitable for WordPress\n';
prompt += '- Include H2 and H3 headings for structure\n';
prompt += '- Use short paragraphs (2-3 sentences max)\n';
prompt += '- Include a compelling introduction and conclusion\n';
prompt += '- Naturally incorporate SEO keywords\n';
prompt += '- Add internal linking suggestions\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "SEO-optimized blog title",\n';
prompt += '  "slug": "url-friendly-slug",\n';
prompt += '  "metaDescription": "155-character meta description",\n';
prompt += '  "content": "full HTML blog post content",\n';
prompt += '  "excerpt": "2-3 sentence excerpt for preview",\n';
prompt += '  "tags": ["tag1", "tag2"],\n';
prompt += '  "categories": ["category1"],\n';
prompt += '  "estimatedWordCount": 0,\n';
prompt += '  "seoScore": "estimated SEO quality: high/medium/low",\n';
prompt += '  "readingTime": "estimated reading time"\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiGenerate.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.input.topic, content: raw, excerpt: '', tags: [], slug: '' }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;
var wpResp = fb($.steps.publishToWordPress.response, {});
var status = fb($.input.publishStatus, 'draft');

var summary = ':white_check_mark: *Blog Post Published to WordPress*\n\n';
summary += '*Title:* ' + (fb(ai.title, 'Untitled')) + '\n';
summary += '*Status:* ' + status + '\n';
summary += '*Slug:* ' + (fb(ai.slug, 'N/A')) + '\n';
summary += '*Word Count:* ~' + (fb(ai.estimatedWordCount, 'N/A')) + '\n';
summary += '*Reading Time:* ' + (fb(ai.readingTime, 'N/A')) + '\n';
summary += '*SEO Score:* ' + (fb(ai.seoScore, 'N/A')) + '\n';
if (ai.metaDescription) summary += '*Meta:* ' + ai.metaDescription + '\n';
var tagList = (fb(ai.tags, [])).join(', ');
if (tagList) summary += '*Tags:* ' + tagList + '\n';
if (wpResp.URL) summary += '*URL:* ' + wpResp.URL + '\n';
if (wpResp.ID) summary += '*Post ID:* ' + wpResp.ID + '\n';

return { summary: summary };
